ValidationRule.errorConditionFormula:
AND(
    OR(
        ISBLANK(Number_Of_Free_Programs_Per_School__c),
        Number_Of_Free_Programs_Per_School__c = 0
    ),
    OR(
        ISBLANK(TEXT(Discount_Eligibility__c)),
        ISPICKVAL(Discount_Eligibility__c, "Paid + Free with PromoCode")
    )
)
